    ]

    // Previous midpoints — all steps before the current one
    const prevRows = []
    for (const r of visibleRows.slice(0, -1)) {
      if (Number.isFinite(r.m) && Number.isFinite(r.fm)) prevRows.push(r)
    }
    if (prevRows.length &gt; 0) {
      const xs = [], ys = [], labels = []
      for (const r of prevRows) {
        xs.push(r.m)
        ys.push(r.fm)
        labels.push(`m${r.n}`)
      }
      data.push({
        x: xs, y: ys,
